import React, { useState } from "react";
import styled, { css, keyframes } from "styled-components";

/**
 * CardAnimation - A component that adds Meta-like hover animations to child elements
 * @param {ReactNode} children - The content to be animated
 * @returns {JSX.Element} - The animated component
 */
const CardAnimation = ({ children }) => {
  const [isHovered, setIsHovered] = useState(false);

  return (
    <AnimationWrapper
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      isHovered={isHovered}
    >
      {children}
    </AnimationWrapper>
  );
};

// Animation keyframes
const pulseAnimation = keyframes`
  0% {
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.05);
    transform: translateY(0);
  }
  50% {
    box-shadow: 0 12px 30px rgba(0, 0, 0, 0.12);
    transform: translateY(-8px);
  }
  100% {
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.05);
    transform: translateY(0);
  }
`;

// Styled components
const AnimationWrapper = styled.div`
  position: relative;
  transition: transform var(--transition-normal), box-shadow var(--transition-normal);

  ${props => props.isHovered && css`
    transform: translateY(-8px);
    box-shadow: var(--shadow-lg);
  `}

  &:hover {
    z-index: 1;
  }

  &:active {
    animation: ${pulseAnimation} 0.4s ease;
  }
`;

export default CardAnimation;
